function SochalionAvatar() {
  return (
    <div style={{
      width: 110,
      height: 110,
      borderRadius: "50%",
      background: "linear-gradient(135deg, #FCD600 0%, #FFB800 100%)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      overflow: "hidden",
      boxShadow: "0 8px 24px rgba(0,61,122,0.5), 0 0 0 4px #003D7A, 0 0 0 8px #FCD600",
      position: "relative",
    }}>
      <img
        src={SOCHALION_BG}
        alt="Sochalion"
        style={{
          width: "180%",
          height: "180%",
          objectFit: "cover",
          objectPosition: "center 22%",
        }}
      />
    </div>
  );
}

function BackgroundPattern() {
  return (
    <>
      {/* Couche 1 : dégradé bleu de base */}
      <div style={{
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: "linear-gradient(180deg, #003D7A 0%, #002855 100%)",
        zIndex: -3,
      }} />
      {/* Couche 2 : Sochalion en arrière-plan */}
      <div style={{
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundImage: `url(${SOCHALION_BG})`,
        backgroundSize: "cover",
        backgroundPosition: "center top",
        backgroundRepeat: "no-repeat",
        opacity: 0.18,
        zIndex: -2,
      }} />
      {/* Couche 3 : halos jaunes pour la profondeur */}
      <div style={{
        position: "fixed",
        top: -100,
        right: -100,
        width: 300,
        height: 300,
        borderRadius: "50%",
        background: "radial-gradient(circle, rgba(252,214,0,0.25) 0%, transparent 70%)",
        zIndex: -1,
        pointerEvents: "none",
      }} />
      <div style={{
        position: "fixed",
        bottom: -150,
        left: -100,
        width: 400,
        height: 400,
        borderRadius: "50%",
        background: "radial-gradient(circle, rgba(252,214,0,0.15) 0%, transparent 70%)",
        zIndex: -1,
        pointerEvents: "none",
      }} />
      <style>{`
        @keyframes pulse {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.1); }
        }
        @keyframes slideIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes livePulse {
          0%, 100% { opacity: 1; box-shadow: 0 0 0 0 rgba(76,175,80,0.7); }
          50% { opacity: 0.6; box-shadow: 0 0 0 6px rgba(76,175,80,0); }
        }
      `}</style>
    </>
  );
}

